import React, { useState, useEffect } from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay, EffectFade, Pagination } from "swiper/modules";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/pagination";
import "./Home.css";
import { useParams } from "react-router-dom";
import Loading from "../../Pages/Loading/Loading";



function Home({ slides }) {
  const { ProductId } = useParams();
  const productIndex = parseInt(ProductId, 10); // Ensure it's a number

  const [loading, setLoading] = useState(true); // Loading state for data
  const [fetchedSlides, setFetchedSlides] = useState(null); // Store slides after "loading"

  useEffect(() => {
    // Simulating a delay to fetch data (e.g., 2 seconds)
    const timer = setTimeout(() => {
      setFetchedSlides(slides); // Set the slides data after "fetching"
      setLoading(false); // End loading after data is "fetched"
    }, 2000); // Simulating a 2-second loading delay

    return () => clearTimeout(timer); // Cleanup timer when component unmounts
  }, [slides]); // Re-run if slides change

  // Show loading page if still loading
  if (loading) {
    return <Loading />;
  }

  // Debug to make sure the productIndex and data are correct
  console.log(fetchedSlides[productIndex]); 

  return (
    <Swiper
      className="home-swiper"
      autoplay={{ delay: 4000 }}
      effect="fade"
      pagination={{
        clickable: true,
        type: "bullets",
      }}
      style={{
        "--swiper-pagination-bullet-active": "#FFFFFF",
        "--swiper-pagination-bullet-active-color": "#ff0000",
      }}
      modules={[EffectFade, Autoplay, Pagination]}
      loop={true}
    >
      {/* Render your slides once the data is available */}
      {fetchedSlides && fetchedSlides[productIndex] && (
        <SwiperSlide className="home-swiper-slide">
          <img
            src={fetchedSlides[productIndex].imageUrl || "/images/HomeSlider/HisteriaMaxBG.jpg"}
            alt={fetchedSlides[productIndex].altText || "Default Alt Text"}
            loading="lazy"
          />
        </SwiperSlide>
      )}

      {/* Default fallback slides (in case productIndex is invalid or no specific data) */}
      {fetchedSlides && (
        <>
          <SwiperSlide className="home-swiper-slide">
            <img
              src="/images/HomeSlider/HisteriaMaxBG.jpg"
              alt="Histeria Max"
              loading="lazy"
            />
          </SwiperSlide>
          <SwiperSlide className="home-swiper-slide">
            <img
              src="/images/HomeSlider/HugyMooshDarkBG.jpg"
              alt="Hugy Moosh"
              loading="lazy"
            />
          </SwiperSlide>
          <SwiperSlide className="home-swiper-slide">
            <img
              src="/images/HomeSlider/HugyMooshWhiteBG.jpg"
              alt="Hugy Moosh White"
              loading="lazy"
            />
          </SwiperSlide>
        </>
      )}
    </Swiper>
  );
}

export default Home;



